oxy_webhelp_navlinks = {"monitor_analyze_ai_agent_activity-d30753e52015":{"topics":[{"title":"Dashboards page","shortdesc":"<p class=\"shortdesc\">The Agent Cloud dashboard gives you an immediate summary of your AI agent environment — agents discovered, high-risk agents, active violations, and active alerts. Start here when you open Agent Cloud.<\/p>","href":"agent_cloud\/dashboards_page.html","attributes":{"data-id":"dashboards_page"},"menu":{"hasChildren":false},"tocID":"dashboards_page-d30753e52029","next":"dashboards_page-d30753e52029"},{"title":"Inventory page","shortdesc":"<p class=\"shortdesc\">The Inventory section shows every AI agent, tool, and model that Agent Cloud has discovered across all your connections. Use it to understand what is running in your environment, review tool authorization status, and identify agents or tools that need attention.<\/p>","href":"agent_cloud\/inventory_page.html","attributes":{"data-id":"inventory_page"},"menu":{"hasChildren":false},"tocID":"inventory_page-d30753e52054","next":"inventory_page-d30753e52054"},{"title":"Posture page","shortdesc":"<p class=\"shortdesc\">The Posture section is where you triage and resolve policy violations. The Violations page shows what Agent Cloud flagged as non-compliant. The Insights page provides AI-generated analysis of agent behavior patterns with remediation recommendations.<\/p>","href":"agent_cloud\/posture_page.html","attributes":{"data-id":"posture_page"},"menu":{"hasChildren":false},"tocID":"posture_page-d30753e52115","next":"posture_page-d30753e52115"},{"title":"Runtime page","shortdesc":"<p class=\"shortdesc\">The Runtime section provides real-time visibility into agent sessions, individual tool calls, and alerts. Use it to investigate a specific incident, trace the sequence of actions in a session, or triage open alerts.<\/p>","href":"agent_cloud\/runtime_page.html","attributes":{"data-id":"runtime_page"},"menu":{"hasChildren":false},"tocID":"runtime_page-d30753e52162","next":"runtime_page-d30753e52162"},{"title":"Connectors page","shortdesc":"<p class=\"shortdesc\">The Connectors page shows all AI platforms and gateways connected to Agent Cloud — their status, tool blocking configuration, and the number of agents discovered through each connection.<\/p>","href":"agent_cloud\/connectors_page.html","attributes":{"data-id":"connectors_page"},"menu":{"hasChildren":false},"tocID":"connectors_page-d30753e52209","next":"connectors_page-d30753e52209"},{"title":"Events page","shortdesc":"<p class=\"shortdesc\">The Events page lists platform-level activity in <span class=\"ph\">Agent Cloud<\/span>, such as         policy updates, connection changes, and gateway configuration updates.<\/p>","href":"agent_cloud\/events_page_agent_cloud.html","attributes":{"data-id":"events_page_agent_cloud"},"menu":{"hasChildren":false},"tocID":"events_page_agent_cloud-d30753e52262","topics":[]}]}};